import { useState, useEffect } from "react";
import { getMissions, getFactureStats, getTrackingStats } from "../services/api";
import { useAuth } from "../context/AuthContext";

const STATUT_BADGE = {
  en_attente: "badge-gray",
  assignee:   "badge-blue",
  en_cours:   "badge-amber",
  livree:     "badge-green",
  incident:   "badge-red",
  annulee:    "badge-gray",
};

export default function Dashboard() {
  const { user } = useAuth();
  const [missions,   setMissions]   = useState([]);
  const [factStats,  setFactStats]  = useState(null);
  const [trackStats, setTrackStats] = useState(null);
  const [loading,    setLoading]    = useState(true);

  useEffect(() => {
    Promise.all([
      getMissions().catch(() => ({ data: [] })),
      getFactureStats().catch(() => null),
      getTrackingStats().catch(() => null),
    ]).then(([m, f, t]) => {
      setMissions(m.data);
      setFactStats(f?.data || null);
      setTrackStats(t?.data || null);
    }).finally(() => setLoading(false));
  }, []);

  const enCours  = missions.filter(m => m.statut === "en_cours").length;
  const livrees  = missions.filter(m => m.statut === "livree").length;
  const incidents= missions.filter(m => m.statut === "incident").length;
  const recentes = [...missions].sort((a,b) => new Date(b.createdAt) - new Date(a.createdAt)).slice(0,5);

  if (loading) return <div className="loading"><div className="spinner"/> Chargement...</div>;

  return (
    <div>
      <div className="topbar">
        <span className="topbar-title">Bonjour, {user?.prenom} 👋</span>
        <span style={{ fontSize:12, color:"var(--gray)" }}>
          {new Date().toLocaleDateString("fr-FR", { weekday:"long", day:"numeric", month:"long" })}
        </span>
      </div>

      <div className="page-content">
        {/* ── Stats ────────────────────────────────────────────────────── */}
        <div className="stats-grid">
          <div className="stat-card">
            <div className="stat-icon blue">🚚</div>
            <div>
              <div className="stat-value">{missions.length}</div>
              <div className="stat-label">Total missions</div>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon amber">⏳</div>
            <div>
              <div className="stat-value">{enCours}</div>
              <div className="stat-label">En cours</div>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon green">✅</div>
            <div>
              <div className="stat-value">{livrees}</div>
              <div className="stat-label">Livrées</div>
            </div>
          </div>
          <div className="stat-card">
            <div className="stat-icon red">⚠️</div>
            <div>
              <div className="stat-value">{incidents}</div>
              <div className="stat-label">Incidents</div>
            </div>
          </div>
          {factStats && (
            <div className="stat-card">
              <div className="stat-icon amber">💶</div>
              <div>
                <div className="stat-value">{factStats.enAttente?.montant?.toFixed(0) || 0}€</div>
                <div className="stat-label">En attente facturation</div>
              </div>
            </div>
          )}
          {factStats && (
            <div className="stat-card">
              <div className="stat-icon green">💰</div>
              <div>
                <div className="stat-value">{factStats.payees?.montant?.toFixed(0) || 0}€</div>
                <div className="stat-label">Facturé & payé</div>
              </div>
            </div>
          )}
        </div>

        {/* ── Missions récentes ────────────────────────────────────────── */}
        <div className="card">
          <div className="card-title">📋 Missions récentes</div>
          {recentes.length === 0 ? (
            <div className="empty-state">
              <div className="icon">🚚</div>
              <p>Aucune mission pour le moment</p>
            </div>
          ) : (
            <div className="table-wrap">
              <table>
                <thead>
                  <tr>
                    <th>Référence</th>
                    <th>Client</th>
                    <th>Départ</th>
                    <th>Arrivée</th>
                    <th>Statut</th>
                    <th>Priorité</th>
                  </tr>
                </thead>
                <tbody>
                  {recentes.map(m => (
                    <tr key={m._id}>
                      <td><b>{m.reference}</b></td>
                      <td>{m.clientNom}</td>
                      <td style={{ maxWidth:160, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{m.adresseDepart}</td>
                      <td style={{ maxWidth:160, overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>{m.adresseArrivee}</td>
                      <td><span className={`badge ${STATUT_BADGE[m.statut] || "badge-gray"}`}>{m.statut}</span></td>
                      <td><span className={`badge ${m.priorite === "urgente" ? "badge-red" : m.priorite === "haute" ? "badge-amber" : "badge-gray"}`}>{m.priorite}</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
